const tasks = [
  // الاثنين (0)
  "📝 نشر بوست على X\n📝 نشر بوست على LinkedIn\n📧 تفقد الإيميلات الشخصية والعمل\n💬 متابعة رسائل واتساب وتيليجرام وفايبر\n🏋️ تدريب رياضي",

  // الثلاثاء (1)
  "📝 نشر بوست على X\n📝 نشر بوست على LinkedIn\n📧 تفقد الإيميلات الشخصية والعمل\n💬 متابعة رسائل واتساب وتيليجرام وفايبر\n🏋️ تدريب رياضي",

  // الأربعاء (2)
  "📝 نشر بوست على X\n📝 نشر بوست على LinkedIn\n🧵 كتابة ثريد على X\n🧵 كتابة ثريد على LinkedIn\n📧 تفقد الإيميلات الشخصية والعمل\n💬 متابعة رسائل واتساب وتيليجرام وفايبر",

  // الخميس (3)
  "📝 نشر بوست على X\n📝 نشر بوست على LinkedIn\n📧 تفقد الإيميلات الشخصية والعمل\n💬 متابعة رسائل واتساب وتيليجرام وفايبر\n🇳🇱 تدريب لغة هولندية\n🏋️ تدريب رياضي",

  // الجمعة (4)
  "📝 نشر بوست على X\n📝 نشر بوست على LinkedIn\n📧 تفقد الإيميلات الشخصية والعمل\n💬 متابعة رسائل واتساب وتيليجرام وفايبر\n🏋️ تدريب رياضي",

  // السبت (5)
  "📝 نشر بوست على X\n📝 نشر بوست على LinkedIn\n📄 كتابة مقالة\n📧 تفقد الإيميلات الشخصية والعمل\n💬 متابعة رسائل واتساب وتيليجرام وفايبر",

  // الأحد (6)
  "📝 نشر بوست على X\n📝 نشر بوست على LinkedIn\n📧 تفقد الإيميلات الشخصية والعمل\n💬 متابعة رسائل واتساب وتيليجرام وفايبر"
];

// جلب العداد
const counter = $getWorkflowStaticData('global').counter || 0;

// اختيار مهمة اليوم
const currentTask = tasks[counter];

// تحديث العداد (0=اثنين, 1=ثلاثاء, ..., 6=أحد ثم يعود للاثنين)
if (counter < tasks.length - 1) {
  $getWorkflowStaticData('global').counter = counter + 1;
} else {
  $getWorkflowStaticData('global').counter = 0;
}

// اقتباسات تحفيزية (30 اقتباس)
const quotes = [
  "من جد وجد ومن زرع حصد",
  "النجاح رحلة وليس وجهة",
  "افعل اليوم ما سيشكرك عليه غداً",
  "كل دقيقة تخطيط توفر 10 دقائق تنفيذ",
  "لا تؤجل عمل اليوم إلى الغد",
  "الاستمرارية تتفوق على الموهبة",
  "الفشل هو أول خطوة نحو النجاح",
  "اجعل من الروتين عادة ومن العادة نجاحاً",
  "العقل السليم في الجسم السليم",
  "تعلم لغة جديدة تفتح لك عالماً جديداً",
  "الرياضة ليست عقاباً بل استثمار في صحتك",
  "كل صباح فرصة جديدة لتبدأ من جديد",
  "النظام هو سر الإنتاجية",
  "لا تقارن نفسك بالآخرين، قارن نفسك بأمسك",
  "التواصل الفعال هو مفتاح العلاقات الناجحة",
  "تعلم شيئاً جديداً كل يوم",
  "الانضباط هو الجسر بين الأهداف والإنجاز",
  "الراحة ليست في عدم العمل، بل في حب ما تعمل",
  "كل خطوة صغيرة تقربك من هدفك الكبير",
  "النجاح هو مجموع الجهود الصغيرة المتكررة يومياً",
  "لا تنتظر الظروف المثالية، اصنعها بنفسك",
  "التخطيط الجيد نصف الإنجاز",
  "الصحة تاج على رؤوس الأصحاء",
  "اللغات جسور بين الثقافات",
  "الرياضة تصفي الذهن وتقوي البدن",
  "كل يوم هو فرصة لتكون أفضل",
  "التواصل الاجتماعي جزء من نجاحك المهني",
  "العادات الصغيرة تبني حياة عظيمة",
  "لا تستسلم، فكل مجهود له ثماره",
  "اجعل حياتك منظمة تعش بسعادة"
];

const quote = quotes[Math.floor(Math.random() * quotes.length)];

// تحديد اسم اليوم
const days = ["الاثنين", "الثلاثاء", "الأربعاء", "الخميس", "الجمعة", "السبت", "الأحد"];
const dayName = days[counter];

return {
  task: currentTask,
  quote: quote,
  day: dayName,
  counter: counter
};
